        raise ValueError("Invalid phone number")

def insert_person_details(avl_tree_root, person_details):
    validate_person_details(person_details)

    person = Person(person_details["name"], person_details["age"], person_details["street"],
                    person_details["city"], person_details["state"], person_details["zip_code"],
                    person_details["phone_number"])

    if avl_tree_root is None:
        avl_tree_root = person
        return avl_tree_root

    if person.age < avl_tree_root.age:
        avl_tree_root.left = insert_person_details(avl_tree_root.left, person)
    else:
        avl_tree_root.right = insert_person_details(avl_tree_root.right, person)

    # Update the height and balance factor of the AVL tree nodes
    avl_tree_root.height = 1 + max(get_height(avl_tree_root.left), get_height(avl_tree_root.right))
    balance_factor = get_balance_factor(avl_tree_root)

    # Perform AVL tree rotations if necessary
    if balance_factor > 1:
        if person.age < avl_tree_root.left.age:
            avl_tree_root = rotate_right(avl_tree_root)
        else:
            avl_tree_root.left = rotate_left(avl_tree_root.left)
            avl_tree_root = rotate_right(avl_tree_root)
    elif balance_factor < -1:
        if person.age > avl_tree_root.right.age:
            avl_tree_root = rotate_left(avl_tree_root)
        else:
            avl_tree_root.right = rotate_right(avl_tree_root.right)
            avl_tree_root = rotate_left(avl_tree_root)

    return avl_tree_root
```

This code defines the necessary functions and classes to populate the person details in an AVL tree while performing the required validations. The `validate_person_details` function validates the person details, and the `insert_person_details` function inserts the validated details into the AVL tree. The AVL tree rotations are performed to maintain the AVL tree property. The time complexity of inserting a person's details and performing the validations is O(log n) due to the use of an AVL tree.

