```python
def get_nested_sum(d):
    """
    Helper function to calculate the sum of all values in a nested dictionary.
    """
    if isinstance(d, dict):
        return sum(get_nested_sum(v) for v in d.values())
    return d

def find_max_element(d):
    max_sum = float('-inf')
    max_element = None

    for key, value in d.items():
        nested_sum = get_nested_sum(value) + sum(get_nested_sum(child) for child in value.values() if isinstance(child, dict))
        if nested_sum > max_sum:
            max_sum = nested_sum
            max_element = key

    return max_element, max_sum

