```python
def merge_dicts(dict1, dict2):
    merged_dict = {}

    # Combine key-value pairs from both dictionaries
    merged_dict.update(dict1)
    merged_dict.update(dict2)

    # Concatenate values for keys present in both dictionaries
    for key in dict1.keys() & dict2.keys():
        if isinstance(dict1[key], str) and isinstance(dict2[key], str):
            merged_dict[key] = dict1[key] + ' ' + dict2[key]
        elif isinstance(dict1[key], list) and isinstance(dict2[key], list):
            merged_dict[key] = dict1[key] + dict2[key]
        elif isinstance(dict1[key], int) and isinstance(dict2[key], int):
            merged_dict[key] = dict1[key] + dict2[key]

    # Remove key-value pairs with negative values
    merged_dict = {key: value for key, value in merged_dict.items() if value >= 0}

    # Sort the merged dictionary by key in ascending order
    merged_dict = dict(sorted(merged_dict.items(), key=lambda x: x[0]))

    # Remove key-value pairs where the key starts with a vowel
    merged_dict = {key: value for key, value in merged_dict.items() if not key[0].lower() in ['a', 'e', 'i', 'o', 'u']}

    # Merge dictionaries recursively for keys present in both dictionaries
    for key in dict1.keys() & dict2.keys():
        if isinstance(dict1[key], dict) and isinstance(dict2[key], dict):
            merged_dict[key] = merge_dicts(dict1[key], dict2[key])

    return merged_dict
```

