import random

def shuffle_list(lst):
    n = len(lst)
    for i in range(n-1, 0, -1):
        # Generate a random index to swap with
        j = random.randint(0, i)
        # Swap elements at indices i and j
        lst[i], lst[j] = lst[j], lst[i]

    return sorted(lst)
```

