To find the median of a large array of integers efficiently, you can use the QuickSelect algorithm, which has an average time complexity of O(n) and a worst-case time complexity of O(n^2) but can be optimized to have an expected time complexity of O(nlogn). 

Here's the Python script that implements the QuickSelect algorithm to find the median:

```python
import random

def partition(arr, low, high):
    # Choosing a random pivot element
    pivot_index = random.randint(low, high)
    pivot = arr[pivot_index]

    # Swapping the pivot element to the end of the array
    arr[pivot_index], arr[high] = arr[high], arr[pivot_index]

    # Partitioning the array
    i = low
    for j in range(low, high):
        if arr[j] <= pivot:
            arr[i], arr[j] = arr[j], arr[i]
            i += 1
    arr[i], arr[high] = arr[high], arr[i]

    return i

def quick_select(arr, low, high, k):
    if low == high:
        return arr[low]

    pivot_index = partition(arr, low, high)

    if k == pivot_index:
        return arr[k]
    elif k < pivot_index:
        return quick_select(arr, low, pivot_index - 1, k)
    else:
        return quick_select(arr, pivot_index + 1, high, k)

def find_median(arr):
    n = len(arr)
    if n % 2 == 0:
        # If the array size is even, return the average of the middle two elements
        median = (quick_select(arr, 0, n-1, n//2-1) + quick_select(arr, 0, n-1, n//2)) / 2
    else:
        # If the array size is odd, return the middle element
        median = quick_select(arr, 0, n-1, n//2)

    return median

# Test the script
arr = [4, 7, 1, 3, 9, 2, 8, 5, 6]
median = find_median(arr)
print("Median:", median)
```

Note that this script uses the random module to choose a random pivot element in the partition function. This helps to avoid the worst-case time complexity of O(n^2) when the input array is already sorted.

