JavaScript function for linear search algorithm (recursive approach):

```javascript
function linearSearchRecursive(array, element, currentIndex = 0, arrayLength = array.length) {
  // Handle case where element is undefined
  if (element === undefined) {
    throw new Error("Element is undefined");
  }

  // Handle case where array is empty
  if (arrayLength === 0) {
    throw new Error("Array is empty");
  }

  // Base case: element not found
  if (currentIndex >= arrayLength) {
    return [];
  }

  // Recursive case: element found
  if (array[currentIndex] === element) {
    const indices = linearSearchRecursive(array, element, currentIndex + 1, arrayLength);
    indices.push(currentIndex);
    return indices;
  }

  // Recursive case: continue searching
  return linearSearchRecursive(array, element, currentIndex + 1, arrayLength);
}
```

