  }

  // Handle case where array is empty
  if (array.length === 0) {
    throw new Error("Array is empty");
  }

  const indices = [];

  for (let i = 0; i < array.length; i++) {
    if (array[i] === element) {
      indices.push(i);
    }

    // If element is found after the current index, stop searching
    if (indices.length > 0 && i > indices[indices.length - 1]) {
