#include <vector>

std::vector<int> linearSearch(std::vector<int> array, int element) {
    // Handle case where array is empty
    if (array.size() == 0) {
        throw std::runtime_error("Array is empty");
    }

    std::vector<int> indices;

    for (int i = 0; i < array.size(); i++) {
        if (array[i] == element) {
            indices.push_back(i);
        }

        // If element is found after the current index, stop searching
        if (indices.size() > 0 && i > indices.back()) {
            break;
        }
    }

    return indices;
}
