    def __init__(self):
        self.database = {}

    def validate_course_id(self, course_id):
        if len(course_id) > 10:
            return False
        if not course_id.isalnum():
            return False
        if not course_id[0].isalpha():
            return False
        return True

    def add_course(self, course_id, course_name, course_description, course_instructor, course_schedule):
        if not self.validate_course_id(course_id):
            return "Invalid Course ID"
        self.database[course_id] = {
            "Course Name": course_name,
            "Course Description": course_description,
            "Course Instructor": course_instructor,
            "Course Schedule": course_schedule
        }
        return "Course added successfully"

    def get_course(self, course_id):
        return self.database.get(course_id)

    def update_course(self, course_id, course_name=None, course_description=None, course_instructor=None, course_schedule=None):
        course = self.database.get(course_id)
        if not course:
            return "Course not found"
        if course_name:
            course["Course Name"] = course_name
        if course_description:
            course["Course Description"] = course_description
        if course_instructor:
            course["Course Instructor"] = course_instructor
        if course_schedule:
            course["Course Schedule"] = course_schedule
        return "Course updated successfully"

    def delete_course(self, course_id):
        if course_id in self.database:
            del self.database[course_id]
            return "Course deleted successfully"
        else:
            return "Course not found"

    def get_courses_reached_max_capacity(self):
        courses_reached_max_capacity = []
        for course_id, course in self.database.items():
            for session in course["Course Schedule"]:
                if session[4] == session[5]:
                    courses_reached_max_capacity.append(course_id)
                    break
        return courses_reached_max_capacity

    def get_available_seats(self, course_id, session_index):
        course = self.database.get(course_id)
        if not course:
            return "Course not found"
        if session_index >= len(course["Course Schedule"]):
            return "Invalid session index"
        session = course["Course Schedule"][session_index]
        return session[5] - session[4]

    def get_total_enrolled_students(self, course_id):
        course = self.database.get(course_id)
        if not course:
            return "Course not found"
        total_enrolled_students = 0
        for session in course["Course Schedule"]:
            total_enrolled_students += session[4]
        return total_enrolled_students

    def get_average_enrolled_students(self):
        total_courses = len(self.database)
        if total_courses == 0:
            return 0
        total_enrolled_students = 0
        for course_id, course in self.database.items():
            for session in course["Course Schedule"]:
                total_enrolled_students += session[4]
        return total_enrolled_students / total_courses

    def get_course_with_highest_enrollment_rate(self):
        highest_enrollment_rate = 0
        course_with_highest_enrollment_rate = None
        for course_id, course in self.database.items():
            total_enrolled_students = 0
            total_available_seats = 0
            for session in course["Course Schedule"]:
                total_enrolled_students += session[4]
                total_available_seats += session[5]
            enrollment_rate = total_enrolled_students / total_available_seats
            if enrollment_rate > highest_enrollment_rate:
                highest_enrollment_rate = enrollment_rate
                course_with_highest_enrollment_rate = course_id
        return course_with_highest_enrollment_rate
