class BigIntNode:
    def __init__(self, value):
        self.value = value
        self.next = None

class BigInt:
    def __init__(self, num_str):
        self.head = None
        self.tail = None
        for digit in num_str:
            self.add_digit(int(digit))

    def add_digit(self, digit):
        new_node = BigIntNode(digit)
        if self.head is None:
            self.head = new_node
            self.tail = new_node
        else:
            self.tail.next = new_node
            self.tail = new_node

    def __str__(self):
        curr = self.head
        result = ""
        while curr:
            result += str(curr.value)
            curr = curr.next
        return result

class Rectangle:
    def __init__(self, length, width):
        if length <= 100 and width <= 100:
            self.length = BigInt(str(length))
            self.width = BigInt(str(width))
        else:
            raise ValueError("Length and width must be <= 100")

    def area(self):
        return int(str(self.length)) * int(str(self.width))

    def perimeter(self):
        return 2 * (int(str(self.length)) + int(str(self.width)))

    def is_square(self):
        return str(self.length) == str(self.width)

    def rotate(self):
        self.length, self.width = self.width, self.length

    def is_golden_rectangle(self):
        longer_side = max(int(str(self.length)), int(str(self.width)))
        shorter_side = min(int(str(self.length)), int(str(self.width)))
        ratio = longer_side / shorter_side
        return abs(ratio - 1.61803398875) < 1e-10
```

