```python
import socket
import ssl

def make_http_request(url: str) -> str:
    try:
        # Parse the URL to get the host and path
        protocol, host, path = parse_url(url)

        # Create a TCP socket
        if protocol == "http":
            sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        elif protocol == "https":
            sock = ssl.create_default_context().wrap_socket(socket.socket(socket.AF_INET, socket.SOCK_STREAM), server_hostname=host)
        else:
            return None

        # Set a timeout for the socket
        sock.settimeout(5)

        # Connect to the host
        sock.connect((host, 80 if protocol == "http" else 443))

        # Send the HTTP GET request
        request = f"GET {path} HTTP/1.1\r\nHost: {host}\r\nConnection: close\r\n\r\n"
        sock.sendall(request.encode())

        # Receive the response
        response = b""
        while True:
            data = sock.recv(4096)
            if not data:
                break
            response += data

        # Close the socket
        sock.close()

        # Parse the response to get the status code and body
        status_code, body = parse_response(response)

        # Handle redirects
        if status_code >= 300 and status_code < 400:
            redirect_url = extract_redirect_url(response)
            if redirect_url:
                return make_http_request(redirect_url)

        # Return the body in case of a successful request
        if status_code == 200:
            return body

    except (socket.timeout, socket.gaierror, ssl.SSLError):
        pass

    return None

def parse_url(url: str) -> tuple:
    if url.startswith("http://"):
        return ("http", url[7:], "/")
    elif url.startswith("https://"):
        return ("https", url[8:], "/")
    else:
        return None

def parse_response(response: bytes) -> tuple:
    headers, body = response.split(b"\r\n\r\n", 1)
    header_lines = headers.split(b"\r\n")
    status_line = header_lines[0]
    status_code = int(status_line.split()[1])
    return (status_code, body.decode())

def extract_redirect_url(response: bytes) -> str:
    headers, _ = response.split(b"\r\n\r\n", 1)
    header_lines = headers.split(b"\r\n")
    for line in header_lines:
        if line.lower().startswith(b"location:"):
            _, redirect_url = line.split(b":", 1)
            return redirect_url.decode().strip()
    return None
```

The implementation first parses the URL to get the protocol, host, and path. It then creates a TCP socket and connects to the host. It sends an HTTP GET request and receives the response. The response is parsed to get the status code and body. If the status code indicates a redirect, the function extracts the redirect URL and makes a new HTTP request to follow the redirect. Finally, the function returns the body in case of a successful request or None in case of an error.

