print(circle.is_point_inside(3, 4))  # Output: True
print(circle.is_point_inside(5, 0))  # Output: False
circle.translate(2, 3)
print(circle.center)  # Output: (2, 3)
circle.change_color("blue")
print(circle.color)  # Output: blue
