```python
class BankAccount:
    def __init__(self, account_number, account_holder_name, initial_balance, account_type):
        self.set_account_number(account_number)
        self.set_account_holder_name(account_holder_name)
        self.set_balance(initial_balance)
        self.set_account_type(account_type)

    def set_account_number(self, account_number):
        if not isinstance(account_number, int) or len(str(account_number)) != 10:
            raise ValueError("Invalid account number")
        self._account_number = account_number

    def get_account_number(self):
        return self._account_number

    def set_account_holder_name(self, account_holder_name):
        if not isinstance(account_holder_name, str) or not account_holder_name.isalpha():
            raise ValueError("Invalid account holder name")
        self._account_holder_name = account_holder_name

    def get_account_holder_name(self):
        return self._account_holder_name

    def set_balance(self, initial_balance):
        if not isinstance(initial_balance, (int, float)) or initial_balance <= 0:
            raise ValueError("Invalid initial balance")
        self._balance = initial_balance

    def get_balance(self):
        return self._balance

    def set_account_type(self, account_type):
        if account_type not in ["savings", "checking"]:
            raise ValueError("Invalid account type")
        self._account_type = account_type

    def get_account_type(self):
        return self._account_type

    def deposit(self, amount):
        if not isinstance(amount, (int, float)) or amount <= 0:
            raise ValueError("Invalid amount")
        self._balance += amount

    def withdraw(self, amount):
        if not isinstance(amount, (int, float)) or amount <= 0:
            raise ValueError("Invalid amount")
        if amount > self._balance:
            raise ValueError("Insufficient funds")
        self._balance -= amount

    def display_details(self):
        print("Account Number:", self._account_number)
        print("Account Holder Name:", self._account_holder_name)
        print("Account Type:", self._account_type)
        print("Current Balance:", self._balance)

    def transfer_funds(self, amount, receiver_account):
        if not isinstance(amount, (int, float)) or amount <= 0:
            raise ValueError("Invalid amount")
        if amount > self._balance:
            raise ValueError("Insufficient funds")

        self._balance -= amount
        receiver_account.deposit(amount)
```

