print(factorial(-3))  # Output: Factorial is not defined for negative numbers
```

In this function, the base cases are defined for when `n` is less than 0 (to handle negative numbers) and when `n` is 0 or 1. For any other positive number, the function recursively calls itself with `n-1` as the argument and multiplies it with `n`. This process continues until `n` reaches 0 or 1, at which point the factorial value is returned.

Here's an implementation of the vector class:

```python
from typing import List

class Vector:
    def __init__(self, vector: List[float]):
        self.vector = vector

    def __str__(self) -> str:
        return f"<Vector: {self.vector}>"

    def add(self, other: 'Vector') -> 'Vector':
        if len(self.vector) != len(other.vector):
            raise ValueError("Vectors must have the same dimension.")
        result = [self.vector[i] + other.vector[i] for i in range(len(self.vector))]
        return Vector(result)

    def subtract(self, other: 'Vector') -> 'Vector':
        if len(self.vector) != len(other.vector):
            raise ValueError("Vectors must have the same dimension.")
        result = [self.vector[i] - other.vector[i] for i in range(len(self.vector))]
        return Vector(result)

    def multiply(self, scalar: float) -> 'Vector':
        result = [scalar * self.vector[i] for i in range(len(self.vector))]
        return Vector(result)

    def dot_product(self, other: 'Vector') -> float:
        if len(self.vector) != len(other.vector):
            raise ValueError("Vectors must have the same dimension.")
        result = sum([self.vector[i] * other.vector[i] for i in range(len(self.vector))])
        return result

    def normalize(self) -> 'Vector':
        magnitude = self.magnitude()
        if magnitude == 0:
            return self
        result = [self.vector[i] / magnitude for i in range(len(self.vector))]
        return Vector(result)

    def magnitude(self) -> float:
        return (sum([x**2 for x in self.vector]))**0.5
```

